    27→import lombok.extern.slf4j.Slf4j;
    28→import net.sf.jsqlparser.expression.Expression;
    29→import net.sf.jsqlparser.expression.Function;
    30→import net.sf.jsqlparser.expression.NullValue;
    31→
    32→import java.util.ArrayList;
    33→import java.util.List;
    34→
    35→/**
    36→ * ConcatWsFunction  ->  concat_ws(string1, string2, string3,...)
    37→ * description:
    38→ * - Return NULL If STRING1 is NULL.
    39→ * - Return a string that concatenates (STRING2, STRING3, ...) with a separator STRING1.
    40→ */
    41→@Slf4j
    42→@TransformFunction(type = FunctionConstant.STRING_TYPE, names = {
    43→        "concat_ws"}, parameter = "(String string1 [, String string2, ...])", descriptions = {
    44→                "- Return NULL If 'STRING1' is NULL;",
    45→                "- Return a string that concatenates ('STRING2', 'STRING3', ...) with a separator STRING1."
    46→        }, examples = {
    47→                "concat_ws('-', 'apple', 'banana', 'cloud') = \"apple-banana-cloud\"",
    48→                "concat_ws('-', 'apple', '', 'cloud') = \"apple--cloud\"",
    49→                "concat_ws('-', 'apple', null, 'cloud') = \"apple-cloud\""
    50→        })
    51→public class ConcatWsFunction implements ValueParser {
    52→
    53→    private final String separator;
    54→    private final List<ValueParser> nodeList;
    55→
    56→    public ConcatWsFunction(Function expr) {
    57→        List<Expression> params = expr.getParameters().getExpressions();
    58→        if (params == null || params.isEmpty()) {
    59→            this.separator = null;
    60→            this.nodeList = new ArrayList<>();
    61→            return;
    62→        }
    63→
    64→        // Handle the case where the separator is NULL
    65→        Expression separatorExpr = params.get(0);
    66→        if (separatorExpr instanceof NullValue) {
    67→            this.separator = null;
    68→        } else {
    69→            this.separator = OperatorTools.parseString(
    70→                    OperatorTools.buildParser(separatorExpr).parse(null, 0, null));
    71→        }
    72→
    73→        this.nodeList = new ArrayList<>(params.size() - 1);
    74→        for (int i = 1; i < params.size(); i++) {
    75→            Expression paramExpr = params.get(i);
    76→            if (paramExpr instanceof NullValue) {
    77→                // Add null to the list to be handled in parse method
    78→                nodeList.add(null);
    79→            } else {
    80→                nodeList.add(OperatorTools.buildParser(paramExpr));
    81→            }
    82→        }
    83→    }
    84→
    85→    @Override
    86→    public Object parse(SourceData sourceData, int rowIndex, Context context) {
    87→        if (separator == null) {
    88→            return null;
    89→        }
    90→        StringBuilder result = new StringBuilder();
    91→        boolean firstStrFlag = true;
    92→        for (ValueParser node : nodeList) {
    93→            if (node != null) {
    94→                Object parsedValue = node.parse(sourceData, rowIndex, context);
    95→                if (parsedValue != null) {
    96→                    if (!firstStrFlag) {
    97→                        result.append(separator);
    98→                    }
    99→                    result.append(parsedValue);
   100→                    firstStrFlag = false;
   101→                }
   102→            }
   103→        }
   104→        return result.toString();
   105→    }
   106→}
