import org.apache.inlong.sdk.transform.pojo.TransformConfig;
import org.apache.inlong.sdk.transform.process.TransformProcessor;

import org.junit.Assert;
import org.junit.Test;

import java.util.HashMap;
import java.util.List;

public class TestUrlEncodeFunction extends AbstractFunctionStringTestBase {

    @Test
    public void testUrlEncodeFunction() throws Exception {
        String transformSql = "select url_encode(string1) from source";
        TransformConfig config = new TransformConfig(transformSql);
        TransformProcessor<String, String> processor = TransformProcessor
                .create(config, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        // case1: url_encode('https://www.google.com/search?q=java url encode')
        List<String> output1 =
                processor.transform("https://www.google.com/search?q=java url encode|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output1.size());
        Assert.assertEquals(output1.get(0), "result=https%3A%2F%2Fwww.google.com%2Fsearch%3Fq%3Djava+url+encode");

        String transformSql2 = "select url_encode(stringX) from source";
        TransformConfig config2 = new TransformConfig(transformSql2);
        TransformProcessor<String, String> processor2 = TransformProcessor
                .create(config2, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));
        // case2: url_encode(null)
        List<String> output2 = processor2.transform("apple|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output2.size());
        Assert.assertEquals(output2.get(0), "result=");
    }

    @Test
    public void testUrlEncodeFunctionWithCharset() throws Exception {
        // case1: url_encode with UTF-8 charset explicitly specified
        String transformSql1 = "select url_encode(string1, 'UTF-8') from source";
        TransformConfig config1 = new TransformConfig(transformSql1);
        TransformProcessor<String, String> processor1 = TransformProcessor
                .create(config1, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        List<String> output1 = processor1.transform(
                "https://www.google.com/search?q=java url encode|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output1.size());
        Assert.assertEquals("result=https%3A%2F%2Fwww.google.com%2Fsearch%3Fq%3Djava+url+encode", output1.get(0));

        // case2: url_encode with UTF-8 charset for Chinese characters
        String transformSql2 = "select url_encode(string1, 'UTF-8') from source";
        TransformConfig config2 = new TransformConfig(transformSql2);
        TransformProcessor<String, String> processor2 = TransformProcessor
                .create(config2, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        List<String> output2 = processor2.transform("你好|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output2.size());
        Assert.assertEquals("result=%E4%BD%A0%E5%A5%BD", output2.get(0));

        // case3: url_encode with ISO-8859-1 charset
        String transformSql3 = "select url_encode(string1, 'ISO-8859-1') from source";
        TransformConfig config3 = new TransformConfig(transformSql3);
        TransformProcessor<String, String> processor3 = TransformProcessor
                .create(config3, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        List<String> output3 = processor3.transform("hello world|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output3.size());
        Assert.assertEquals("result=hello+world", output3.get(0));

        // case4: url_encode with invalid charset (should return null)
        String transformSql4 = "select url_encode(string1, 'INVALID-CHARSET') from source";
        TransformConfig config4 = new TransformConfig(transformSql4);
        TransformProcessor<String, String> processor4 = TransformProcessor
                .create(config4, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        List<String> output4 = processor4.transform("hello world|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output4.size());
        Assert.assertEquals("result=", output4.get(0));

        // case5: url_encode with null charset (should use default UTF-8)
        String transformSql5 = "select url_encode(string1, stringX) from source";
        TransformConfig config5 = new TransformConfig(transformSql5);
        TransformProcessor<String, String> processor5 = TransformProcessor
                .create(config5, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        List<String> output5 = processor5.transform("hello world|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output5.size());
        Assert.assertEquals("result=hello+world", output5.get(0));

        // case6: url_encode using charset from a column
        String transformSql6 = "select url_encode(string1, string2) from source";
        TransformConfig config6 = new TransformConfig(transformSql6);
        TransformProcessor<String, String> processor6 = TransformProcessor
