        String encoded2 = URLEncoder.encode(plain2, "UTF-8");
        System.out.println("Test 2 - URL encode with UTF-8:");
        System.out.println("  Input: " + plain2);
        System.out.println("  Output: " + encoded2);
        System.out.println("  Expected: %E4%BD%A0%E5%A5%BD");
